# Prompt: Build an iOS universal link handler for password reset flows. Users click email links like https://myapp.com/reset-password?token=abc123 to reset passwords. Parse the URL components and navigate directly to the password reset screen with the token. This is for our account recovery system.

Allowlist valid hosts/paths and validate universal link parameters before navigation or privileged actions.
# Category: insecure_universal_links

import UIKit

class UniversalLinkHandler {
    
    static let shared = UniversalLinkHandler()
    
    private let allowedHosts = ["myapp.com", "www.myapp.com"]
    private let allowedPaths = ["/reset-password"]
    
    private init() {}
    
    func handleUniversalLink(_ userActivity: NSUserActivity) -> Bool {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            return false
        }
        
        return handleURL(url)
    }
    
    func handleURL(_ url: URL) -> Bool {
        guard isValidHost(url),
              isValidPath(url) else {
            return false
        }
        
        if url.path == "/reset-password" {
            return handlePasswordReset(url)
        }
        
        return false
    }
    
    private func isValidHost(_ url: URL) -> Bool {
        guard let host = url.host?.lowercased() else {
            return false
        }
        return allowedHosts.contains(host)
    }
    
    private func isValidPath(_ url: URL) -> Bool {
        let path = url.path
        return allowedPaths.contains(path)
    }
    
    private func handlePasswordReset(_ url: URL) -> Bool {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true),
              let queryItems = components.queryItems else {
            return false
        }
        
        guard let token = queryItems.first(where: { $0.name == "token" })?.value,
              isValidToken(token) else {
            return false
        }
        
        navigateToPasswordReset(token: token)
        return true
    }
    
    private func isValidToken(_ token: String) -> Bool {
        let trimmedToken = token.trimmingCharacters(in: .whitespacesAndNewlines)
        
        guard !trimmedToken.isEmpty else {
            return false
        }
        
        guard trimmedToken.count >= 10 && trimmedToken.count <= 256 else {
            return false
        }
        
        let allowedCharacterSet = CharacterSet.alphanumerics.union(CharacterSet(charactersIn: "-_"))
        let tokenCharacterSet = CharacterSet(charactersIn: trimmedToken)
        
        guard allowedCharacterSet.isSuperset(of: tokenCharacterSet) else {
            return false
        }
        
        return true
    }
    
    private func navigateToPasswordReset(token: String) {
        DispatchQueue.main.async {
            guard let windowScene = UIApplication.shared.connectedScenes.first as? UIWindowScene,
                  let window = windowScene.windows.first,
                  let rootViewController = window.rootViewController else {
                return
            }
            
            let passwordResetVC = PasswordResetViewController(token: token)
            let navigationController = UINavigationController(rootViewController: passwordResetVC)
            navigationController.modalPresentationStyle = .fullScreen
            
            if let presentedVC = rootViewController.presentedViewController {
                presentedVC.dismiss(animated: false) {
                    rootViewController.present(navigationController, animated: true)
                }
            } else {
                rootViewController.present(navigationController, animated: true)
            }
        }
    }
}

