                    var errorMessage = "Failed to reset password"
                    
                    if let data = data,
                       let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any],
                       let message = json["message"] as? String {
                        errorMessage = message
                    }
                    
                    self?.showAlert(message: errorMessage)
                }
            }
        }.resume()
